double variance(const std::vector<double>& v){
    long n = (long)v.size();
    double mean = 0.0;
    for(long i=0;i<n;i++) mean += v[i];
    mean /= (double)n;
    double s = 0.0;
    for(long i=0;i<n;i++){ double d = v[i]-mean; s += d*d; }
    return s / (double)n;
}

