bool armstrong_check(long n){
    long x = n;
    long digits = 0;
    while(x > 0){ digits++; x /= 10; }
    x = n;
    long s = 0;
    while(x > 0){
        long d = x % 10;
        long p = 1;
        for(long i=0;i<digits;i++) p *= d;
        s += p;
        x /= 10;
    }
    return s == n;
}

